def render_response(intent: str, lang: str, default_lang: str = 'en') -> str:
    lang_map = _RESPONSES.get(lang) or _RESPONSES.get(default_lang, {})
    return lang_map.get(intent) or _RESPONSES.get(default_lang, {}).get('fallback', '')
